function isComponentBlock(items: any[]): boolean {
  return items.length === 3 && items.every((i) => i.type === items[0].type);
}

const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
  rune: 60,
};

function calculateBasePremium(items: any[]): number {
  if (isComponentBlock(items)) {
    return COMPONENT_BLOCK_PREMIUM[items[0].type];
  }
  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
}

function calculatePremium(items: any[]): number {
  const basePremium = calculateBasePremium(items);
  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
}

